# eval/mutation_runner.py
"""Apply GenAI-specific mutations to the eval harness and run tests."""
import ast, copy, importlib, subprocess, pathlib, sys, json
from typing import Callable

HARNESS_PATH = pathlib.Path("eval/harness.py")
TESTS_PATH = "tests/eval/"

class MutationResult:
    def __init__(self, name: str, killed: bool, surviving_code: str = ""):
        self.name = name
        self.killed = killed
        self.surviving_code = surviving_code

def apply_mutation(source: str, mutator: Callable[[ast.AST], ast.AST]) -> str:
    tree = ast.parse(source)
    new_tree = mutator(copy.deepcopy(tree))
    return ast.unparse(new_tree)

# Operator 1: weaken all >= comparisons to >= 0.0
class AssertionWeakener(ast.NodeTransformer):
    def visit_Compare(self, node):
        self.generic_visit(node)
        if any(isinstance(op, ast.GtE) for op in node.ops):
            node.comparators = [ast.Constant(value=0.0) for _ in node.comparators]
        return node

# Operator 2: replace judge() calls with lambda always returning True
class JudgeBypasser(ast.NodeTransformer):
    def visit_Call(self, node):
        self.generic_visit(node)
        if isinstance(node.func, ast.Name) and node.func.id in ("judge", "judge_assert", "score"):
            return ast.Constant(value=True)
        return node

def run_tests_on_mutation(mutant_code: str) -> bool:
    """Write mutant to temp file, run tests, return True if tests FAIL (mutant killed)."""
    tmp = pathlib.Path("/tmp/harness_mutant.py")
    tmp.write_text(mutant_code)
    # Monkey-patch the module path
    result = subprocess.run(
        [sys.executable, "-m", "pytest", TESTS_PATH, "--import-mode=importlib",
         "--co", "-q", "--timeout=30"],
        capture_output=True, text=True,
        env={"PYTHONPATH": str(tmp.parent), **dict(__import__("os").environ)},
    )
    return result.returncode != 0   # non-zero = test caught the mutant

OPERATORS = [
    ("assertion_weakener", AssertionWeakener()),
    ("judge_bypasser", JudgeBypasser()),
]

def run_mutation_suite() -> list[MutationResult]:
    source = HARNESS_PATH.read_text()
    results = []
    for name, operator in OPERATORS:
        mutant_code = apply_mutation(source, operator)
        killed = run_tests_on_mutation(mutant_code)
        if not killed:
            results.append(MutationResult(name, killed=False, surviving_code=mutant_code[:300]))
        else:
            results.append(MutationResult(name, killed=True))
        print(f"  {'KILLED' if killed else 'SURVIVED'} {name}")
    return results

if __name__ == "__main__":
    results = run_mutation_suite()
    killed = sum(1 for r in results if r.killed)
    score = killed / len(results) * 100 if results else 0
    print(f"\nMutation score: {killed}/{len(results)} = {score:.1f}%")
    for r in results:
        if not r.killed:
            print(f"  SURVIVOR: {r.name}")
            print(f"    {r.surviving_code}")
    if score < 85.0:
        sys.exit(1)
